import { styled } from 'styled-components';

import UIImage from '#components/Image';
import { TILE_WIDTH_MOBILE } from '#components/ProductCarousel';

import * as breakpoint from '#theme/breakPoints';
import { visuallyHidden } from '#theme/mixins';

import { HeadingProps, ValueProps } from './Table.types';

export const Boundary = styled.div`
  overflow: hidden;
  max-width: 100%;
  overflow-x: auto;
`;

export const Image = styled(UIImage)`
  max-width: ${TILE_WIDTH_MOBILE}px;
  height: auto;
  aspect-ratio: 3/2;
`;

interface ComparisonTableProps {
  readonly $columns: number;
}

export const ComparisonTable = styled.section<ComparisonTableProps>`
  --columns: ${({ $columns }) => $columns};
  display: grid;
  width: max-content;
  grid-template-columns: repeat(var(--columns), 140px);
  grid-template-rows:
    [hero] repeat(2, min-content)
    [specs] repeat(9, min-content)
    [buttons] repeat(2, min-content);
  grid-auto-columns: ${TILE_WIDTH_MOBILE}px;
  grid-auto-flow: column;
  column-gap: ${({ theme }) => theme.spacing.x2}px;
  padding: ${({ theme }) => theme.spacing.x2}px
    ${({ theme }) => theme.spacing.x4}px;
  margin: 0 auto;
  text-align: center;
`;

export const Hero = styled.header`
  grid-template-rows: subgrid;
  grid-row: hero / span 2;
  margin: 0;
`;

export const Name = styled.h2`
  margin: 0;
  font: ${({ theme }) => theme.textStyle.productComparisonTable.productName};
  padding-block: ${({ theme }) => theme.spacing.x1_5}px;
`;

export const List = styled.dl`
  display: grid;
  grid-template-rows: subgrid;
  grid-row: specs / span 9;
  margin-block-start: 0;
`;

export const Cell = styled.div`
  display: flex;
  flex-direction: column;
  gap: ${({ theme }) => theme.spacing.x0_5}px;
  border-bottom: 1px solid ${({ theme }) => theme.color.divider.light};
  background-color: ${({ theme }) => theme.color.canvas.secondary};
  padding-block: ${({ theme }) => theme.spacing.x1}px;
  padding-inline: ${({ theme }) => theme.spacing.x1_5}px;

  &:first-child {
    border-top: 1px solid ${({ theme }) => theme.color.divider.light};
  }
`;

export const Heading = styled.dt<HeadingProps>`
  font: ${({ theme }) => theme.textStyle.productComparisonTable.specHeading};
  ${({ $hidden }) => ($hidden ? visuallyHidden : '')};
`;

export const Value = styled.dd<ValueProps>`
  margin: 0;
  font: ${({ theme, $bold }) =>
    $bold
      ? theme.textStyle.productComparisonTable.specHeading
      : theme.textStyle.productComparisonTable.specValue};

  &:empty {
    &::before {
      /* an em dash */
      content: '\u2014';
    }
  }
`;

export const ButtonGroup = styled.div`
  display: grid;
  grid-template-columns: subgrid;
  grid-template-rows: subgrid;
  grid-auto-flow: column;
  grid-column: 1 / -1;
  grid-row: buttons / span 2;
  row-gap: ${({ theme }) => theme.spacing.x2}px;

  @media (min-width: ${breakpoint.tablet}px) {
    display: none;
  }
`;
