/* eslint-disable react/prop-types */
import { Fragment, FC } from 'react';

import Button from '#components/Button';
import { BUTTON_AS_ANCHOR } from '#components/Button/Button.constants';
import StarRating from '#components/StarRating';

import {
  BUY_NOW_TARGET,
  BUY_NOW_TEXT,
  BUY_NOW_VARIANT,
  REVIEW_TARGET,
  REVIEW_TEXT,
  REVIEW_VARIANT,
  SPEC_PRICE_KEY,
  SPEC_RATING_KEY,
  SPEC_RATING_SIZE,
  SPEC_RATING_TOTAL,
} from './Table.constants';
import {
  Boundary,
  ComparisonTable,
  Hero,
  Name,
  List,
  Cell,
  Heading,
  Value,
  Image,
  ButtonGroup,
} from './Table.styles';
import { Props, Specs } from './Table.types';

interface SpecProps {
  specs: Specs;
}

const Specifications: FC<SpecProps> = ({ specs }) => (
  <Fragment>
    {specs.map((spec) => {
      const { key } = spec;

      if (key === SPEC_RATING_KEY) {
        const { rating } = spec;
        return (
          <Cell key={key}>
            <Heading>{key}</Heading>
            <Value>
              <StarRating
                size={SPEC_RATING_SIZE}
                value={rating}
                total={SPEC_RATING_TOTAL}
              />
            </Value>
          </Cell>
        );
      }

      const { value } = spec;
      const isPrice = key === SPEC_PRICE_KEY;

      return (
        <Cell key={key}>
          <Heading $hidden={isPrice}>{key}</Heading>
          <Value $bold={isPrice}>{value}</Value>
        </Cell>
      );
    })}
  </Fragment>
);

const Table = (props: Props) => {
  const { items = [], onBuyClick, onReviewClick } = props;
  return (
    <Boundary>
      <ComparisonTable $columns={items.length}>
        {items.map(({ id, image, title, productSpecs }) => (
          <Fragment key={id}>
            <Hero key={id}>
              <Image src={image.url} alt={image.alt} />
              <Name>{title}</Name>
            </Hero>
            <List>
              <Specifications specs={productSpecs} />
            </List>
          </Fragment>
        ))}
        <ButtonGroup>
          {items.map(({ id, buyNow, readReview }) => (
            <Fragment key={id}>
              <Button
                as={BUTTON_AS_ANCHOR}
                variant={BUY_NOW_VARIANT}
                href={buyNow.vendorLink}
                target={BUY_NOW_TARGET}
                isExternal={buyNow.isExternal}
                onClick={onBuyClick}
              >
                {BUY_NOW_TEXT}
              </Button>
              <Button
                variant={REVIEW_VARIANT}
                data-href={readReview.anchorHref}
                target={REVIEW_TARGET}
                onClick={onReviewClick}
              >
                {REVIEW_TEXT}
              </Button>
            </Fragment>
          ))}
        </ButtonGroup>
      </ComparisonTable>
    </Boundary>
  );
};

export default Table;
